import{_ as a,c as e,o as l,ag as t}from"./chunks/framework.B-XtCDNB.js";const D=JSON.parse('{"title":"Getting Started with LinkedQL","description":"","frontmatter":{},"headers":[],"relativePath":"docs.md","filePath":"docs.md"}'),n={name:"docs.md"};function o(p,s,i,r,c,d){return l(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="getting-started-with-linkedql" tabindex="-1">Getting Started with LinkedQL <a class="header-anchor" href="#getting-started-with-linkedql" aria-label="Permalink to &quot;Getting Started with LinkedQL&quot;">​</a></h1><p>This guide is the shortest path into the project.</p><p>By the end of it, you should understand three things:</p><ul><li>what you install</li><li>which client shape fits your runtime</li><li>what the common query interface looks like</li></ul><p>If you want the broader philosophy first, start with <a href="/overview">What is LinkedQL</a>. If you want the full local runtime story, jump to <a href="/flashql">FlashQL</a>.</p><h2 id="project-shape" tabindex="-1">Project shape <a class="header-anchor" href="#project-shape" aria-label="Permalink to &quot;Project shape&quot;">​</a></h2><p>LinkedQL has two layers that are worth separating mentally:</p><ul><li>the <strong>common client contract</strong>: <code>query()</code>, <code>stream()</code>, <code>transaction()</code>, <code>wal.subscribe()</code></li><li>the <strong>richer runtime layers</strong> built on top of that contract, especially FlashQL</li></ul><p>That distinction matters because it keeps the docs honest:</p><ul><li>every client does not do everything</li><li>but the way you talk to data stays intentionally similar across runtimes</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Install the package from npm:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">npm</span><span style="color:#C3E88D;"> install</span><span style="color:#C3E88D;"> @linked-db/linked-ql</span></span></code></pre></div><p>The package exports client entry points such as:</p><ul><li><code>@linked-db/linked-ql/postgres</code></li><li><code>@linked-db/linked-ql/mysql</code></li><li><code>@linked-db/linked-ql/mariadb</code></li><li><code>@linked-db/linked-ql/edge</code></li><li><code>@linked-db/linked-ql/edge-worker</code></li><li><code>@linked-db/linked-ql/flashql</code></li></ul><h2 id="current-shape" tabindex="-1">Current shape <a class="header-anchor" href="#current-shape" aria-label="Permalink to &quot;Current shape&quot;">​</a></h2><p>LinkedQL is no longer just a sketch of an idea. It is already a substantial, tested system with a large and growing test base across parsing, desugaring, execution, realtime behavior, sync behavior, edge transport, and storage behavior.</p><p>The practical way to read its maturity today is:</p><ul><li>strong already in the core client contract</li><li>strong already in FlashQL, live queries, local-first orchestration, and version-aware querying</li><li>still catching up in some broader DDL and migration-oriented surfaces</li></ul><p>That is a more useful framing than either &quot;fully done&quot; or &quot;just alpha.&quot;</p><h2 id="dialects-clients-and-runtimes" tabindex="-1">Dialects, clients, and runtimes <a class="header-anchor" href="#dialects-clients-and-runtimes" aria-label="Permalink to &quot;Dialects, clients, and runtimes&quot;">​</a></h2><p>LinkedQL gives you several entry points depending on where the query should run.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Client</th><th style="text-align:left;">Use it when</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><code>PGClient</code></td><td style="text-align:left;">your app talks directly to PostgreSQL</td><td style="text-align:left;"><a href="/docs/setup#postgresql">Dialects &amp; Clients</a></td></tr><tr><td style="text-align:left;"><code>MySQLClient</code></td><td style="text-align:left;">your app talks directly to MySQL</td><td style="text-align:left;"><a href="/docs/setup#mysql">Dialects &amp; Clients</a></td></tr><tr><td style="text-align:left;"><code>MariaDBClient</code></td><td style="text-align:left;">your app talks directly to MariaDB</td><td style="text-align:left;"><a href="/docs/setup#mariadb">Dialects &amp; Clients</a></td></tr><tr><td style="text-align:left;"><code>EdgeClient</code></td><td style="text-align:left;">your app talks to a remote worker/server that exposes LinkedQL over HTTP or worker ports</td><td style="text-align:left;"><a href="/docs/setup#edgeclient">Dialects &amp; Clients</a></td></tr><tr><td style="text-align:left;"><code>FlashQL</code></td><td style="text-align:left;">you want an embeddable local SQL runtime</td><td style="text-align:left;"><a href="/docs/setup#flashql">Dialects &amp; Clients</a></td></tr></tbody></table><p>The important thing is not just the list. It is the architectural freedom this gives you:</p><ul><li>direct server DB access</li><li>edge transport to a remote database runtime</li><li>a full local runtime in-browser, in-worker, or in-process</li></ul><h2 id="first-example-direct-database-client" tabindex="-1">First example: direct database client <a class="header-anchor" href="#first-example-direct-database-client" aria-label="Permalink to &quot;First example: direct database client&quot;">​</a></h2><p>Here is the most familiar starting point: PostgreSQL.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> PGClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  port</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 5432</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">myapp</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 10 AS value</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ value: 10 }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Why this is a good starting point:</p><ul><li>it looks like the mainstream DB client flow developers already know</li><li>it lets you learn the LinkedQL query contract without learning FlashQL first</li></ul><h2 id="second-example-local-runtime-with-flashql" tabindex="-1">Second example: local runtime with FlashQL <a class="header-anchor" href="#second-example-local-runtime-with-flashql" aria-label="Permalink to &quot;Second example: local runtime with FlashQL&quot;">​</a></h2><p>Here is the smallest useful FlashQL setup.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  CREATE TABLE public.users (</span></span>
<span class="line"><span style="color:#C3E88D;">    id INT PRIMARY KEY,</span></span>
<span class="line"><span style="color:#C3E88D;">    name TEXT</span></span>
<span class="line"><span style="color:#C3E88D;">  )</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  INSERT INTO public.users (id, name)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;Ada&#39;), (2, &#39;Linus&#39;)</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ id: 1, name: &#39;Ada&#39; }, { id: 2, name: &#39;Linus&#39; }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Why this example matters:</p><ul><li>it shows that FlashQL is not &quot;mock SQL&quot;; it is a real local SQL runtime</li><li>it uses the same <code>query()</code> shape as the mainstream clients</li><li>it is the shortest path into local-first patterns later</li></ul><h2 id="what-comes-after-these-first-examples" tabindex="-1">What comes after these first examples <a class="header-anchor" href="#what-comes-after-these-first-examples" aria-label="Permalink to &quot;What comes after these first examples&quot;">​</a></h2><p>The two examples above deliberately stay simple. But the same API family quickly expands into richer ground:</p><ul><li>live queries with <code>{ live: true }</code></li><li>lazy result streaming with <code>db.stream()</code></li><li>table-level changefeeds with <code>db.wal.subscribe()</code></li><li>syntax extensions such as DeepRefs and structured writes</li><li>FlashQL orchestration with foreign namespaces, <code>origin</code>/<code>materialized</code>/<code>realtime</code> views, and <code>db.sync.sync()</code></li></ul><p>That is the general picture to keep in mind as you move deeper into the docs:</p><ul><li>Section 1 of the README introduces the common interface</li><li>Section 2 introduces the language model</li><li>Section 3 introduces orchestration and architecture</li><li>the docs site is where those topics are expanded in full</li></ul><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="/docs/setup">Dialects &amp; Clients</a> for setup by runtime</li><li><a href="/docs/query-api">Query Interface</a> for the common method contract</li><li><a href="/capabilities">Capabilities Overview</a> for the language and runtime extensions</li><li><a href="/flashql">FlashQL</a> for the local runtime and sync model</li></ul>`,42)])])}const h=a(n,[["render",o]]);export{D as __pageData,h as default};
